UIHelper = {}

local function setGUIBySetting(window, settings, functionName)
    for key, setting in pairs(settings) do
        local win = window[functionName](window, key)
        if win then
            for name, value in pairs(setting) do
                if name == "Text" then
                    win:SetText(Lang:getString(value))
                else
                    win:SetProperty(name, value)
                end
            end
        end
    end
end

function UIHelper:setLayoutUIBySetting(layout, settings)
    setGUIBySetting(layout, settings, "getChildWindow")
end

function UIHelper:setWindowUIByJson(window, settings)
    setGUIBySetting(window, settings, "getChildWindowByName")
end

local function getImageSize(imageName, maxWidth, maxHeight)
    local imageInfo = StringUtil.split(imageName, " ")
    if #imageInfo ~= 2 then
        return { 1, 0 }, { 1, 0 }
    end
    local imageset = GUIImagesetManager.Instance():findImageSetByName(imageInfo[1]:gsub("set:", ""))
    if not imageset then
        return { 1, 0 }, { 1, 0 }
    end
    local image = imageset:GetImage(imageInfo[2]:gsub("image:", ""))
    if not image then
        return { 1, 0 }, { 1, 0 }
    end
    local width = image:GetWidth()
    local height = image:GetHeight()
    if width > maxWidth then
        height = (maxWidth / width) * height
        width = maxWidth
    end
    if height > maxHeight then
        width = (maxHeight / height) * width
        height = maxHeight
    end
    return { 0, width }, { 0, height }
end

function UIHelper:setImageAdjustSize(window, image, maxWidth, maxHeight)
    if not window then
        return
    end
    maxWidth = maxWidth or window:GetPixelSize().x
    maxHeight = maxHeight or window:GetPixelSize().y
    window:SetImage(image)
    local width, height = getImageSize(image, maxWidth, maxHeight)
    window:SetWidth(width)
    window:SetHeight(height)
end

local function initClientUI(setting)
    require "base.ui.layout.GUICommonActivityShowReward"
    initCommonActivityShowReward()
    CommonActivityShowReward.setAlwaysOnTop(true)

    require "base.ui.layout.GUICommonActivityRewardPreview"
    initCommonActivityRewardPreview()
    CommonActivityRewardPreview.setAlwaysOnTop(true)

    local UICommonActivityMain = require "base.ui.layout.GUICommonActivityMain"
    GUICommonActivityMain = UICommonActivityMain.new("CommonActivityMain.json", GUIManager:getMainControl())
    GUICommonActivityMain:show()
    UIHelper:setLayoutUIBySetting(GUICommonActivityMain, setting.MainUI)

    local UICommonActivityLayout = require "base.ui.layout.GUICommonActivityLayout"
    GUICommonActivityLayout = UICommonActivityLayout.new("CommonActivityLayout.json")
    GUICommonActivityLayout:hide(true)
    UIHelper:setLayoutUIBySetting(GUICommonActivityLayout, setting.LayoutUI)

    local UICommonActivityTextDialog = require "base.ui.layout.GUICommonActivityTextDialog"
    GUICommonActivityTextDialog = UICommonActivityTextDialog.new("CommonActivityTextDialog.json")
    GUICommonActivityTextDialog:hide()

    local UICommonActivityGrandPrize = require "base.ui.layout.GUICommonActivityGrandPrize"
    GUICommonActivityGrandPrize = UICommonActivityGrandPrize.new("CommonActivityGrandPrize.json")
    GUICommonActivityGrandPrize:setAlwaysOnTop(true)
    GUICommonActivityGrandPrize:hide()
end

