local ShowRule = { None = 0, EveryDayFirst = 1, EveryLogin = 2 }

local CurrentActivityList = {}
function CommonActivity:init(setting)
    initClientUI(setting)
    CurrentActivityList = {}
    CommonDataEvents:registerCallBack("SyncCommonActivity", function(data)
        for _, item in pairs(data) do
            local activity = CommonActivityConfig:getActivityById(item.id)
            if activity then
                for key, value in pairs(item) do
                    activity[key] = value
                end
                self:addActivity(activity)
            end
        end
    end, JsonBuilderProcessor)

    CommonDataEvents:registerCallBack("AddCommonActivity", function(data)
        local activity = CommonActivityConfig:getActivityById(data.id)
        if activity then
            for key, value in pairs(data) do
                activity[key] = value
            end
            self:addActivity(activity)
        end
    end, JsonBuilderProcessor)

    CommonDataEvents:registerCallBack("RemoveCommonActivity", function(data)
        local activity = CommonActivityConfig:getActivityById(data.activityId)
        if activity then
            self:removeActivity(activity)
        end
    end, JsonBuilderProcessor)
    LuaTimer:schedule(function()
        if setting.ShowRule == ShowRule.EveryLogin then
            GUIManager:addShowQueue(GUICommonActivityLayout)
        end
        if setting.ShowRule == ShowRule.EveryDayFirst then
            local day = tostring(DateUtil.getYearDay())
            local key = Game.GameType .. "CommonActivityShowDay"
            if ClientHelper.getStringForKey(key) ~= day then
                ClientHelper.putStringForKey(key, day)
                GUIManager:addShowQueue(GUICommonActivityLayout)
            end
        end
    end, setting.ShowDelay or 3000)
end

function CommonActivity:addActivity(activity)
    table.insert(CurrentActivityList, activity)
    ---启动活动
    GUICommonActivityLayout:addActivity(activity)
end

function CommonActivity:removeActivity(activity)
    TableUtil.tableRemove(CurrentActivityList, activity)
    ---关闭活动
    GUICommonActivityLayout:removeActivity(activity)
    GUICommonActivityMain:checkRedPoint()
end

function CommonActivity:getCurrentActivityList()
    return CurrentActivityList
end